回归 OI 了！打算用这套题来练手，来找一找感觉，然后开始学习。 这是一场 Div.4，难度较低。 A. YES or YES? Portal. 利用常量数组可以简单地实现。以此判断三个字母，代码如下： 123456789101112131415161718192021222324#include &lt;iostream&gt;#include &lt;string&gt;#include &lt;cstdio&gt;using namespace std;int main(void)&#123; const string a = &quot;YES&quot;, b = &quot;yes&quot;; int t; cin &gt;&gt; t; while (t--) &#123; string s; bool flag = true; cin &gt;&gt; s; for (int i = 0; i &lt; 3; ++i) if (s[i] != a[i] &amp;&amp; s[i] != b[i]) flag = false; if (flag) puts(&quot;YES&quot;); else puts(&quot;NO&quot;); &#125; return 0;&#125; B. ICPC Balloons Portal. 利用一个数组记录这个字母之前是否出现过即可，代码如下： 1234567891011121314151617181920212223242526#include &lt;iostream&gt;#include &lt;string&gt;#include &lt;cstring&gt;using namespace std;int main(void)&#123; int T, n; string s; bool flag[30]; cin &gt;&gt; T; while (T--) &#123; cin &gt;&gt; n &gt;&gt; s; int ans = 0; memset(flag, 0, sizeof(flag)); for (int i = 0; i &lt; n; ++i) &#123; if (!flag[s[i] - &#x27;A&#x27;]) ++ans, flag[s[i] - &#x27;A&#x27;] = true; ++ans; &#125; cout &lt;&lt; ans &lt;&lt; &#x27;
&#x27;; &#125; return 0;&#125; C. Cypher Portal. 按顺序模拟即可，代码如下： 1234567891011121314151617181920212223242526272829#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;string&gt;using namespace std;int main(void)&#123; int T, n, b, a[105]; cin &gt;&gt; T; string s; while (T--) &#123; cin &gt;&gt; n; for (int i = 1; i &lt;= n; ++i) cin &gt;&gt; a[i]; for (int i = 1; i &lt;= n; ++i) &#123; cin &gt;&gt; b &gt;&gt; s; for (int j = 0; j &lt; b; ++j) &#123; a[i] += (s[j] == &#x27;D&#x27;) ? (1) : (-1); if (a[i] == 10) a[i] = 0; if (a[i] == -1) a[i] = 9; &#125; cout &lt;&lt; a[i] &lt;&lt; &#x27; &#x27;; &#125; putchar(&#x27;
&#x27;); &#125; return 0;&#125; D. Double Strings Portal. 注意到字符串的长度很短，直接枚举前缀同时计算后缀，再利用集合（当然可以写字符串哈希）判断是否存在即可。代码如下： 12345678910111213141516171819202122232425262728293031323334353637383940#include &lt;iostream&gt;#include &lt;string&gt;#include &lt;unordered_set&gt;using namespace std;string s[100005];unordered_set &lt;string&gt; us;int main(void)&#123; ios::sync_with_stdio(false); cin.tie(0); int t, n; cin &gt;&gt; t; while (t--) &#123; us.clear(); cin &gt;&gt; n; for (int i = 1; i &lt;= n; ++i) cin &gt;&gt; s[i], us.insert(s[i]); for (int i = 1; i &lt;= n; ++i) &#123; bool flag = false; string a = &quot;&quot;, b = s[i]; for (int j = 0; j &lt; s[i].length() - 1; ++j) &#123; a += s[i][j], b.erase(b.begin()); if (us.find(a) != us.end() &amp;&amp; us.find(b) != us.end()) &#123; flag = true; break; &#125; &#125; putchar(flag ? &#x27;1&#x27; : &#x27;0&#x27;); &#125; putchar(&#x27;
&#x27;); &#125; return 0;&#125; E. Mirror Grid Portal. 经典题。找规律找到旋转后的坐标，模拟即可。 123456789101112131415161718192021222324252627282930313233343536373839404142#include &lt;cstdio&gt;#include &lt;string&gt;#include &lt;iostream&gt;using namespace std;bool a[105][105];int main(void)&#123; int t, n; scanf(&quot;%d&quot;, &amp;t); while (t--) &#123; scanf(&quot;%d&quot;, &amp;n); string s; for (int i = 0; i &lt; n; ++i) &#123; cin &gt;&gt; s; for (int j = 0; j &lt; n; ++j) a[i][j] = s[j] - &#x27;0&#x27;; &#125; int ans = 0; for (int i = 0; i &lt; n / 2 + 1; ++i) for (int j = 0; j &lt; n / 2 + 1; ++j) &#123; int s = a[i][j] + a[j][n - i - 1] + a[n - i - 1][n - j - 1] + a[n - j - 1][i]; if (s &lt;= 2) &#123; a[i][j] = a[j][n - i - 1] = a[n - i - 1][n - j - 1] = a[n - j - 1][i] = 0; ans += s; &#125; else &#123; a[i][j] = a[j][n - i - 1] = a[n - i - 1][n - j - 1] = a[n - j - 1][i] = 1; ans += 4 - s; &#125; &#125; printf(&quot;%d
&quot;, ans); &#125; return 0;&#125;
